function flattenValues(obj: Record<string, unknown>): string[] {
  return Object.values(obj).flatMap(v =>
    typeof v === 'string' ? [v]
      : typeof v === 'object' && v !== null ? flattenValues(v as Record<string, unknown>)
      : []
  )
}

